if (! function_exists('text_word_scramble')) {
    function text_word_scramble($text, $mode)
    {
        $words = preg_split('/\s+/', trim($text));
        if (count($words) === 0) {
            return json_encode(['error' => 'Empty input', 'original' => $text]);
        }

        switch ($mode) {
            case 'shuffle_words':
                $shuffled = $words;
                shuffle($shuffled);
                $output = implode(' ', $shuffled);
                break;
            
            case 'reverse_words':
                $output = implode(' ', array_reverse($words));
                break;
            
            case 'shuffle_letters':
                $result = [];
                foreach ($words as $word) {
                    $letters = str_split($word);
                    shuffle($letters);
                    $result[] = implode('', $letters);
                }
                $output = implode(' ', $result);
                break;
            
            case 'middle':
                $result = [];
                foreach ($words as $word) {
                    $len = strlen($word);
                    if ($len <= 3) {
                        $result[] = $word;
                    } else {
                        $first = $word[0];
                        $last = $word[$len - 1];
                        $middle = str_split(substr($word, 1, $len - 2));
                        shuffle($middle);
                        $result[] = $first . implode('', $middle) . $last;
                    }
                }
                $output = implode(' ', $result);
                break;
            
            default:
                return json_encode(['error' => "Unknown mode: $mode"]);
        }

        return json_encode([
            'original' => $text,
            'scrambled' => $output,
            'mode' => $mode,
            'word_count' => count($words),
            'char_count' => strlen($output)
        ]);
    }
